class Solution {
    public int[] earliestAndLatest(int n, int firstPlayer, int secondPlayer) {
        int[] rounds = new int[2];

        if (firstPlayer == secondPlayer) {
            rounds[0] = 1;
            rounds[1] = 1;
            return rounds;
        }

        int firstPlayerIndex = firstPlayer - 1;
        int secondPlayerIndex = secondPlayer - 1;

        if (firstPlayerIndex > secondPlayerIndex) {
            rounds[0] = firstPlayerIndex + 1;
            rounds[1] = secondPlayerIndex + 1;
        } else {
            rounds[0] = secondPlayerIndex + 1;
            rounds[1] = firstPlayerIndex + 1;
        }

        while (firstPlayerIndex >= secondPlayerIndex) {
            rounds[0]++;
            rounds[1]++;
            if (firstPlayerIndex > secondPlayerIndex) {
                rounds[0]++;
                rounds[1]++;
            } else {
                rounds[0]++;
                rounds[1]++;
            }
        }

        return rounds;
    }
}
